function ResultCard({ result }) {
  if (!result) return null;

  return (
    <div className="result-card">
      <h2>Extracted Morphological Features</h2>

      <p>Length: {result.length_cm} cm</p>
      <p>Thickness: {result.thickness_cm} cm</p>
      <p>Perimeter: {result.perimeter_cm} cm</p>
      <p>Area: {result.area_cm2} cm²</p>
      <p>Volume: {result.volume_proxy_cm3} cm³</p>

      <h2>Weight Estimation</h2>

      <p>
        Predicted Weight: {result.predicted_weight_g} g
      </p>
    </div>
  );
}

export default ResultCard;
